	// timeline functions:
	this.frame_14 = function() {
		// Gunakan .bind(this) agar fungsi mengenali timeline utama
		this.btn_home.addEventListener("click", fl_ClickToGoToScene.bind(this));
		
		function fl_ClickToGoToScene() {
		    // Di HTML5 Canvas, tidak ada sistem 'Scene'. 
		    // Kita langsung menuju indeks frame (Frame 1 = indeks 0).
		    // Jika 'home' adalah label frame, gunakan kutip: "home"
		    exportRoot.gotoAndStop("home");
		}
	}
	this.frame_28 = function() {
		this.stop();
		var root = this;
		
		// ================= DATA 10 SOAL =================
		// Di FRAME 1
		window.masterSoal = [
		    {frm:29, k:"D"}, // Frame 30
		    {frm:30, k:"D"}, // Frame 31
		    {frm:31, k:"C"}, // Frame 32
		    {frm:32, k:"D"}, // Frame 33
		    {frm:33, k:"C"}, // Frame 34
		    {frm:34, k:"D"}, // Frame 35
		    {frm:35, k:"D"}, // Frame 36
		    {frm:36, k:"D"}, // Frame 37
		    {frm:37, k:"D"}, // Frame 38
		    {frm:38, k:"D"}  // Frame 39
		];
		
		window.soalAcak = [];
		window.indeks = 0;
		window.skorBenar = 0;
		window.jawabanUser = "";
		
		// ================= FUNGSI ACAK =================
		function shuffle(array){
		    for (var i = array.length - 1; i > 0; i--) {
		        var j = Math.floor(Math.random() * (i + 1));
		        
		        var temp = array[i];
		        array[i] = array[j];
		        array[j] = temp;
		    }
		    return array;
		}
		
		// ================= BUTTON MULAI =================
		root.btn_mulai.cursor = "pointer";
		root.btn_mulai.mouseEnabled = true;
		root.btn_mulai.removeAllEventListeners();
		
		root.btn_mulai.on("click", function(){
		
		    // Reset nilai
		    window.indeks = 0;
		    window.skorBenar = 0;
		    window.jawabanUser = "";
		
		    // Acak soal
		    window.soalAcak = shuffle(window.masterSoal.slice());
		
		    // Pindah ke soal pertama
		    root.gotoAndStop(window.soalAcak[window.indeks].frm);
		});
	}
	this.frame_29 = function() {
		this.stop();
		var root = this;
		
		// ================= 1. GUARD (Mencegah Error jika Data Kosong) =================
		// Jika karena suatu hal data soal belum siap, balikkan ke Frame 1
		if (!window.soalAcak || window.soalAcak.length === 0) {
		    root.gotoAndStop(0); 
		}
		
		// ================= 2. TAMPILAN NOMOR SOAL =================
		if (root.no_soal) {
		    root.no_soal.text = String(window.indeks + 1);
		}
		
		// ================= 3. RESET STATE FRAME =================
		window.jawabanUser = "";
		root.btn_next.visible = false; // Sembunyikan tombol next sampai user pilih jawaban
		
		// Pastikan semua tombol jawaban muncul kembali
		root.btn_a.visible = true;
		root.btn_b.visible = true;
		root.btn_c.visible = true;
		root.btn_d.visible = true;
		
		// ================= 4. SETUP TOMBOL (EVENT LISTENERS) =================
		let tombolJawaban = [root.btn_a, root.btn_b, root.btn_c, root.btn_d];
		
		// Bersihkan listener lama agar tidak terjadi penumpukan (double click)
		tombolJawaban.forEach(function(btn) {
		    btn.cursor = "pointer";
		    btn.removeAllEventListeners("click");
		});
		root.btn_next.removeAllEventListeners("click");
		
		// ================= 5. FUNGSI PILIH JAWABAN =================
		function pilih(p) {
		    window.jawabanUser = p;
		
		    // Sembunyikan tombol yang tidak dipilih (Efek Visual)
		    root.btn_a.visible = (p === "A");
		    root.btn_b.visible = (p === "B");
		    root.btn_c.visible = (p === "C");
		    root.btn_d.visible = (p === "D");
		
		    // Tampilkan tombol Next
		    root.btn_next.visible = true;
		    root.btn_next.cursor = "pointer";
		}
		
		// Pasang Event ke tombol-tombol
		root.btn_a.on("click", function() { pilih("A"); });
		root.btn_b.on("click", function() { pilih("B"); });
		root.btn_c.on("click", function() { pilih("C"); });
		root.btn_d.on("click", function() { pilih("D"); });
		
		// ================= 6. LOGIKA TOMBOL NEXT =================
		root.btn_next.on("click", function() {
		    if (window.jawabanUser === "") return;
		
		    // Cek apakah jawaban benar
		    if (window.jawabanUser === window.soalAcak[window.indeks].k) {
		        window.skorBenar++;
		    }
		
		    // Naikkan urutan soal
		    window.indeks++;
		
		    // Cek navigasi
		    if (window.indeks < window.soalAcak.length) {
		        // Lanjut ke frame soal berikutnya sesuai hasil acak
		        root.gotoAndStop(window.soalAcak[window.indeks].frm);
		    } else {
		        // Jika sudah soal terakhir, pergi ke FRAME HASIL (Frame 40 = index 39)
		        root.gotoAndStop(39); 
		    }
		});
	}
