	// timeline functions:
	this.frame_0 = function() {
		var self = this;
		this.stop();
		
		// 1. DAFTAR ALAT MEJA 3 (Update: 4 Alat)
		var alatBenarArr3 = [
		    this.tabung_reaksi3, 
		    this.stand_kecil3, 
		    this.gula3, 
		    this.garam3
		];
		
		// Alat salah (opsional, sesuaikan instance name jika ada alat pengganggu)
		var alatSalahArr3 = [this.pemanas_lama]; 
		var semuaAlat3 = alatBenarArr3.concat(alatSalahArr3);
		
		var alatDiMeja3 = [];
		var checkArr3 = [];
		
		// 2. SETUP CHECKLIST (Check 1 sampai 4)
		for (var i = 1; i <= 4; i++) {
		    var chk = this["check" + i]; 
		    if (chk) {
		        checkArr3.push(chk);
		        chk.visible = false; 
		    }
		}
		
		this.btnNext3.visible = false;
		
		// 3. FUNGSI DRAG & DROP
		semuaAlat3.forEach(function(alat) {
		    if (!alat) return;
		
		    alat.startX = alat.x;
		    alat.startY = alat.y;
		    alat.cursor = "pointer";
		
		    alat.on("mousedown", function(evt) {
		        self.addChild(alat); 
		        var p = self.globalToLocal(evt.stageX, evt.stageY);
		        alat.offset = { x: alat.x - p.x, y: alat.y - p.y };
		    });
		
		    alat.on("pressmove", function(evt) {
		        var p = self.globalToLocal(evt.stageX, evt.stageY);
		        alat.x = p.x + alat.offset.x;
		        alat.y = p.y + alat.offset.y;
		    });
		
		    alat.on("pressup", function(evt) {
		        var meja = self.meja3_mc; // Pastikan instance name meja di stage adalah meja3_mc
		        var localPos = meja.globalToLocal(evt.stageX, evt.stageY);
		
		        if (meja.hitTest(localPos.x, localPos.y)) {
		            var index = alatBenarArr3.indexOf(alat);
		
		            if (index !== -1) {
		                // BENAR
		                alat.mouseEnabled = false;
		                alat.cursor = "default";
		                
		                if (alatDiMeja3.indexOf(alat) === -1) {
		                    alatDiMeja3.push(alat);
		                }
		
		                // AKTIFKAN CHECKLIST (Urutan sesuai index di alatBenarArr3)
		                if (checkArr3[index]) {
		                    checkArr3[index].visible = true;
		                }
		
		                createjs.Tween.get(alat).to({ scale: 1.1 }, 100).to({ scale: 1 }, 100);
		                cekKelengkapanMeja3();
		            } else {
		                // SALAH (Bukan alat pratikum 3)
		                balikKeRak3(alat);
		            }
		        } else {
		            // LEPAS DI LUAR MEJA
		            balikKeRak3(alat);
		        }
		    });
		});
		
		// 4. FUNGSI PENDUKUNG
		function balikKeRak3(obj) {
		    createjs.Tween.get(obj, { override: true })
		        .to({ x: obj.startX, y: obj.startY }, 500, createjs.Ease.backOut);
		}
		
		function cekKelengkapanMeja3() {
		    // Tombol muncul jika 4 alat sudah benar di meja
		    if (alatDiMeja3.length >= alatBenarArr3.length) {
		        self.btnNext3.visible = true;
		    }
		}
		
		// 5. TOMBOL NEXT
		this.btnNext3.on("click", function() {
		    // Sembunyikan alat dan checklist sebelum pindah
		    semuaAlat3.forEach(function(a) { if(a) a.visible = false; });
		    checkArr3.forEach(function(c) { if(c) c.visible = false; });
		    
		    // Pindah ke frame tujuan berikutnya (misal frame 40)
		    self.gotoAndPlay(1); 
		});
		// Gunakan .bind(this) agar fungsi mengenali timeline utama
		this.btn_home.addEventListener("click", fl_ClickToGoToScene.bind(this));
		
		function fl_ClickToGoToScene() {
		    // Di HTML5 Canvas, tidak ada sistem 'Scene'. 
		    // Kita langsung menuju indeks frame (Frame 1 = indeks 0).
		    // Jika 'home' adalah label frame, gunakan kutip: "home"
		    exportRoot.gotoAndStop("home");
		}
		// Pastikan instance name di panel Properties adalah btn_up
		this.btn_up.addEventListener("click", btn_up_p.bind(this));
		
		function btn_up_p() {
			// exportRoot digunakan untuk mengendalikan Timeline Utama (Stage)
			// Angka 0 adalah indeks untuk kembali ke Frame 1
			exportRoot.gotoAndStop("pilih_praktikum");
		}
	}
